FIX CRITICAL: In /app/frontend/src/pages/HomePage.jsx, move the setPointerCapture call OUT of onPointerDown. Only call e.currentTarget.setPointerCapture(e.pointerId) inside onPointerMove at the moment horizontal lock is established (when |dx| > 8 and |dx| > |dy|). This preserves the swipe-from-keypad fix (capture engages once movement is horizontal so subsequent moves complete the gesture) while letting pure taps (no movement) bypass capture so the click reaches the keypad button normally. Recommended diff:

  const onPointerDown = (e) => {
    if (e.pointerType === 'mouse' && e.button !== 0) return;
    // DO NOT setPointerCapture here
    trackerRef.current = { startX: e.clientX, startY: e.clientY, lock: null, pointerId: e.pointerId, swiped: false };
    setDragging(true);
  };

  const onPointerMove = (e) => {
    const t = trackerRef.current;
    if (!dragging || e.pointerId !== t.pointerId) return;
    const dx = e.clientX - t.startX;
    const dy = e.clientY - t.startY;
    if (!t.lock) {
      if (Math.abs(dx) < 8 && Math.abs(dy) < 8) return;
      t.lock = Math.abs(dx) > Math.abs(dy) ? 'h' : 'v';
      if (t.lock === 'v') { setDragging(false); return; }
      if (t.lock === 'h') {
        try { e.currentTarget.setPointerCapture(e.pointerId); } catch (_) {}
      }
    }
    ...
  };
